-- Control Escolar ITM - Script MySQL
-- Generado: 2026-03-02 (America/Mexico_City)
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
DROP DATABASE IF EXISTS control_escolar_itm;
CREATE DATABASE control_escolar_itm CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci;
USE control_escolar_itm;
CREATE TABLE carreras (
  id_carrera INT PRIMARY KEY AUTO_INCREMENT,
  codigo VARCHAR(10) NOT NULL UNIQUE,
  nombre VARCHAR(120) NOT NULL
) ENGINE=InnoDB;

CREATE TABLE alumnos (
  id_alumno INT PRIMARY KEY AUTO_INCREMENT,
  matricula VARCHAR(20) NOT NULL UNIQUE,
  nombre VARCHAR(120) NOT NULL,
  email VARCHAR(120) NOT NULL,
  id_carrera INT NOT NULL,
  semestre TINYINT NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_alumnos_carreras FOREIGN KEY (id_carrera) REFERENCES carreras(id_carrera)
) ENGINE=InnoDB;

CREATE TABLE maestros (
  id_maestro INT PRIMARY KEY AUTO_INCREMENT,
  num_empleado VARCHAR(20) NOT NULL UNIQUE,
  nombre VARCHAR(120) NOT NULL,
  email VARCHAR(120) NOT NULL,
  id_carrera INT NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_maestros_carreras FOREIGN KEY (id_carrera) REFERENCES carreras(id_carrera)
) ENGINE=InnoDB;

CREATE TABLE cursos (
  id_curso INT PRIMARY KEY AUTO_INCREMENT,
  clave VARCHAR(20) NOT NULL UNIQUE,
  nombre VARCHAR(120) NOT NULL,
  id_carrera INT NOT NULL,
  id_maestro INT NOT NULL,
  dia_semana ENUM('Lunes','Martes','Miércoles','Jueves','Viernes') NOT NULL,
  hora_inicio TIME NOT NULL,
  hora_fin TIME NOT NULL,
  aula VARCHAR(20) NOT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_cursos_carreras FOREIGN KEY (id_carrera) REFERENCES carreras(id_carrera),
  CONSTRAINT fk_cursos_maestros FOREIGN KEY (id_maestro) REFERENCES maestros(id_maestro),
  CONSTRAINT chk_horario CHECK (hora_inicio >= '07:00:00' AND hora_fin <= '13:00:00' AND hora_inicio < hora_fin)
) ENGINE=InnoDB;

CREATE TABLE inscripciones (
  id_inscripcion BIGINT PRIMARY KEY AUTO_INCREMENT,
  id_alumno INT NOT NULL,
  id_curso INT NOT NULL,
  periodo VARCHAR(10) NOT NULL,
  calificacion DECIMAL(4,2) NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY uq_alumno_curso_periodo (id_alumno, id_curso, periodo),
  CONSTRAINT fk_insc_alumnos FOREIGN KEY (id_alumno) REFERENCES alumnos(id_alumno),
  CONSTRAINT fk_insc_cursos FOREIGN KEY (id_curso) REFERENCES cursos(id_curso)
) ENGINE=InnoDB;

